}

 /* 창팝위키에서 수정됨 */
 /**
 * Styling for links generated by [[미디어위키:Edittools]] in WikimediaUI inspired theme.
 * @source https://www.mediawiki.org/wiki/Extension:CharInsert#Styling
 * @updated 2020-03-17
 */

.mw-editTools{
	background-color: var( --background-color-neutral, #eaecf0);
}

#mw-edittools-charinsert {
	padding: 1em 1em 0 1em;
}

#mw-edittools-charinsert > div {
	display: inline-block;
	width: auto;
}

.mw-charinsert-item {
	background-color: var( --background-color-interactive-subtle, #f8f9fa );
	border: var( --border-subtle );
	border-radius: var( --border-radius-base );
	padding: 4px 8px;
	font-size: var( --font-size-small );
	white-space: nowrap;
	box-shadow: 0 1px 0 0 #a2a9b1; /* Codex - var(box-shadow-small-bottom) */
	color: var(--color-base, #202122);
	text-decoration: none;
}

.mw-charinsert-item:hover {
	background-color: var(--background-color-base, #fff);
}

.mw-charinsert-item:active {
	background-color: var(--background-color-interactive, #eaecf0);
	border-color: var(--border-color-interactive--active, #202122);
}

.mw-charinsert-item:focus {
	border-color: var(--border-color-progressive--focus, #36c);
	box-shadow: inset 0 0 0 1px var(--box-shadow-color-progressive--focus, #36c)
}

.client-js .mw-charinsert-item {
	display: inline;
	line-height: 2.5em;
}

/* 가사 이름공간에서 숨기기 */
.ns-3200 .mw-editTools {
	display: none;
}

function moveElementBeforeClass(elementToMove, target) {
  // 옮기려는 요소를 찾습니다.
  const element = document.querySelector(elementToMove);
  if (!element) {
    console.error(`"${elementToMove}" 요소를 찾을 수 없습니다.`);
    return;
  }

  // 특정 클래스를 가진 첫 번째 요소를 찾습니다.
  const targetElement = document.querySelector(target);
  if (!targetElement) {
    console.error(`"${target}" 요소를 찾을 수 없습니다.`);
    return;
  }

  // 기준 요소의 부모 노드를 얻습니다.
  const parent = targetElement.parentNode;
  if (!parent) {
    console.error("기준 요소의 부모 노드를 찾을 수 없습니다.");
    return;
  }

  // 옮기려는 요소를 기준 요소의 바로 앞에 삽입합니다.
  parent.insertBefore(element, targetElement);
}

// 사용 예시:
// <div id="item-to-move">이동할 아이템</div>
// <div class="target-class">기준 아이템 1</div>
// <div class="target-class">기준 아이템 2</div>

moveElementBeforeClass(".mw-editTools", ".editOptions");

/*
 * 원본: https://www.mediawiki.org/wiki/MediaWiki:Gadget-Edittools.js
 */
console.log('EditTools 스크립트 시작');

(function (mw) {
  "use strict";

  var conf, editTools, sections;

  conf = {
    initialSubset: window.EditTools_initial_subset === undefined ? window.EditTools_initial_subset : 0
  };

  editTools = {
    /**
     * Creates the selector
     */
    setup: function () {
      var container, select, initial;
      container = document.getElementById('mw-edittools-charinsert');
      if (!container) {
        return;
      }

      sections = container.querySelectorAll('.mw-edittools-section');
      if (sections.length <= 1) {
        // Only care if there is more than one
        return;
      }

		// 감싸는 div 생성
      var selectWrapper = document.createElement('div');
      selectWrapper.classList.add('oo-ui-widget', 'oo-ui-widget-enabled', 'oo-ui-inputWidget', 'oo-ui-dropdownInputWidget');

      select = document.createElement('select');
      select.style.display = 'inline';
      select.classList.add('oo-ui-inputWidget-input', 'oo-ui-indicator-down');

      initial = conf.initialSubset;
      if (isNaN(initial) || initial < 0 || initial >= sections.length) {
        initial = 0;
      }

      sections.forEach(function (section, i) {
        var sectionTitle, option;
        sectionTitle = section.dataset.sectionTitle;
        option = document.createElement('option');
        option.textContent = sectionTitle;
        option.value = i.toString();
        option.selected = (i === initial);
        select.appendChild(option);
      });

      select.addEventListener('change', editTools.handleOnchange);

      // select 요소를 감싸는 div에 추가
      selectWrapper.appendChild(select);

      // 감싸는 div를 container에 prepend
      container.prepend(selectWrapper);
      editTools.chooseSection(initial);
    },

    /**
     * Handle onchange event of the <select>
     *
     * @param {Event} e
     */
    handleOnchange: function (e) {
      editTools.chooseSection(Number(e.target.value));
      return true;
    },

    /**
     * Toggle the currently visible section
     *
     * @param {Number} sectionNum
     */
    chooseSection: function (sectionNum) {
      var choice = sections[sectionNum];
      if (!choice) {
        return;
      }

      choice.style.display = 'inline';
      sections.forEach(function (section) {
        if (section !== choice) {
          section.style.display = 'none';
        }
      });
    }
  };

  $(function() {
    editTools.setup();
  });
}(mediaWiki));

.ts-doc-sandbox .mbox-image	{
	padding:.75em 0 .75em .75em;
}

.ts-doc-doc {
	clear: both;
	background-color: #eaf3ff;
	color: var(--color-base, #202122);
	border: 1px solid #a3caff;
	margin-top: 1em;
	border-top-left-radius: 2px;
	border-top-right-radius: 2px;
}

.ts-doc-header {
	background-color: #cbd6f6;
	color: var(--color-base, #202122);
	padding: .642857em 1em .5em;
	border-top-left-radius: 2px;
	border-top-right-radius: 2px;
}

.ts-doc-heading {
	display: inline-block;
	padding-left: 30px;
	background: center left / 24px 24px no-repeat;
	/* @noflip */
	background-image: url( https://upload.wikimedia.org/wikipedia/commons/f/fb/OOjs_UI_icon_puzzle-ltr.svg );
	height: 24px;
	line-height: 24px;
	font-weight: 600;
	letter-spacing: 1px;
	text-transform: uppercase;
}

.ts-doc-header .ts-tlinks-tlinks {
	line-height: 24px;
	margin-left: 0;
}

.ts-doc-header .ts-tlinks-tlinks a {
	color: var(--color-progressive, #36c);
}

.ts-doc-header .ts-tlinks-tlinks a:active {
	color: var(--color-progressive--active, #233566);
}

.ts-doc-header .ts-tlinks-tlinks a:visited {
	color: var(--color-visited, #6a60b0);
}

.ts-doc-header .ts-tlinks-tlinks a:visited:active {
	color: var(--color-visited--active, #233566);
}

.ts-doc-content {
	padding: .214286em 1em;
}

.ts-doc-content:after {
	content: '';
	clear: both;
	display: block;
}

.ts-doc-content > :first-child {
	margin-top: .5em;
}

.ts-doc-content > :last-child {
	margin-bottom: .5em;
}

.ts-doc-footer {
	background-color: #eaf3ff;
	color: var(--color-base, #202122);
	border: 1px solid #a3caff;
