.ts-subtitle {
	text-align: center; 
	margin-block: 0.5rem; 
	font-weight: 500;
}

.ts-title {
	text-align: center;
	font-size: 3rem;
	margin-block-start: 0.3em;
}

.ts-welcome {
	text-align: center; 
}

.ts-layout-container {
	display: flex;
	gap: 12px;
	flex-wrap: wrap;
}

.ts-layout-item {
	flex: 1;
	flex-basis: 480px;
}

.ts-search {
	padding: 1rem;
	margin-top: 1.5rem;
	margin-left: auto;
	margin-right: auto;
	max-width: 480px;
	cursor: pointer;
	text-align: center;
	transition-property: background-color, color, border-color, box-shadow;
	transition-duration: .25s;
}

.ts-search:hover {
	border-color: #a14ceb !important; 
	background-color: unset !important; 
}

.ts-search:active {
	border-color: #a14ceb !important;
	box-shadow: inset 0 0 0 1px #a14ceb;
}

.ts-search-icon {
	margin-right: 1rem;
	opacity: 0.6;
}

.ns-3200 pre {
  font-family: sans-serif;
}

