mw.hook('wikipage.content').add(function() {

  // --- 초기 상태 설정 ---
  document.querySelectorAll('.mw-collapsible .mw-collapsible-content').forEach(function(content) {
      content.style.opacity = 1;
      content.style.maxHeight = content.scrollHeight + 'px';
  });

  document.querySelectorAll('.mw-collapsible.mw-collapsed .mw-collapsible-content').forEach(function(content) {
      content.style.display = 'none';
      content.style.opacity = 0;
      content.style.maxHeight = 0;
  });

  // --- 클릭 이벤트 설정 ---
  document.querySelectorAll('.mw-collapsible-toggle').forEach(function(toggle) {
    if (toggle.dataset.customToggleApplied) return;
    toggle.dataset.customToggleApplied = 'true';

    // 토글 영역 위에 올려진 링크를 클릭할 때 토글까지 반응하지 않도록
    toggle.querySelectorAll('a').forEach(function(link) {
	    link.addEventListener('click', function(event) {
	      event.stopPropagation();
	    });
	});

	// 기본 이벤트 비활성화
    toggle.addEventListener('click', function(e) {
      e.stopPropagation();
      e.stopImmediatePropagation();

      const container = this.closest('.mw-collapsible');
      const icon = container.querySelector('.mw-ui-icon-wikimedia-collapse');
      const content = container.querySelector('.mw-collapsible-content');

      if (!container || !content) return;
      const isCollapsed = container.classList.contains('mw-collapsed');

      if (isCollapsed) {
	    container.classList.remove('mw-collapsed');
	    content.style.display = 'block';
	    const scrollHeight = content.scrollHeight;

	    requestAnimationFrame(function() {
	      content.style.opacity = '1';
	      content.style.maxHeight = scrollHeight + 'px';
	       icon.style.transform = 'none';
	    });
      } 
      else {
        content.style.opacity = '0';

        content.style.maxHeight = content.scrollHeight + 'px';

        requestAnimationFrame(function() {
          content.style.maxHeight = '0';
          icon.style.transform = 'rotate(180deg)';
        });

        content.addEventListener('transitionend', function() {
          content.style.display = 'none';
          container.classList.add('mw-collapsed');
        }, { once: true });
      }
    });
  });
});

.ts--navbox .mw-collapsible-content {
  transition: 
  	opacity 0.3s ease-out,
  	max-height 0.2s cubic-bezier(.77,0,.18,1);
  overflow: hidden;
}

.ts--navbox.mw-collapsible.mw-collapsed .mw-collapsible-toggle .mw-ui-icon-wikimedia-collapse{
	transform: rotate(180deg);
}

.ts--navbox.mw-collapsible .mw-collapsible-toggle{
	float: none;
	display: flex; 
	justify-content: space-between; 
	align-items: center; 
	padding: 0.75rem 1rem;
	background-color: var(--background-color-neutral-subtle);
}

.skin-citizen .ts--navbox.mw-collapsible .mw-collapsible-toggle {
	background-color: var(--color-surface-1);
}

.ts--navbox.mw-collapsible.mw-collapsed .mw-collapsible-toggle {
	background-color: transparent;
}

.ts--navbox .mw-collapsible-toggle .mw-ui-icon-wikimedia-collapse {
	transition: transform 0.2s ease;
}

.ts--navbox.mw-collapsible .mw-collapsible-toggle:hover {
	background-color: var(--background-color-button-quiet--hover);
}

.ts--navbox .mw-collapsible-toggle:hover .mw-ui-icon-wikimedia-collapse::before {
	background-color: var(--color-progressive);
}

.ts--imageitem-container {
	position: relative;
	display: flex;
	flex-direction: column;
}

.ts--imageitem-image {
	margin: 0;
	width: 100%;
}

.ts--imageitem-image > img {
	width: 100%;
}

.ts--imageitem-imagelink {
	position: absolute;
	top: 0;
	width: 100%;
	height: 100%;
}

.ts--imageitem-imagelink > a {
	display: block;
	width: 100%;
	height: 100%;
	font-size: 0;
	background: linear-gradient( to bottom, rgba(0,0,0,0.4) 0%, transparent 40%, transparent);
	opacity: 0;
	transition: opacity .135s cubic-bezier(0,0,.2,1);
}

.ts--imageitem-imagelink > a:hover {
	opacity: 1;
}

.ts--imageitem-imagelink > a:active {
	box-shadow: 0 0 0 2px var(--color-progressive);
	transition-duration: 0s;
}

.ts--imageitem-blur-background {
	position: absolute;
	width: 100%;
	z-index: -1;
}

.ts--imageitem-blur-background > img {
	filter: blur(2em) brightness(0.6) saturate(3);
	width: 200%;
	transform: translateX(-25%) translateY(-50%);
}

.ts--imageitem-caption {
	display: flex;
	width: 100%;
	justify-content: center;
	overflow: hidden;
	position: relative;
}

.ts--imageitem-caption a {
	color: white;
	padding: 6px;
	overflow: hidden;
	text-overflow: ellipsis;
	white-space: nowrap;
}

