[[분류:창드컵 수록곡]]

local p = {}
function p.main(frame)
-- 인자 받기 local args = { pageName = frame.args["문서이름"] or frame.args[1] }
-- 인자로 빈 문자열이 전달되었다면 nil로 처리 if args.pageName == "" then args.pageName = nil end
-- pageName 인자가 없다면 현재 페이지의 이름을 사용 local pageName = args.pageName or mw.title.getCurrentTitle().fullText
local title = mw.title.new(pageName, 'Template') local content = title:getContent()
if not content then return "''내용 없음''" end
return frame:extensionTag{ name = 'syntaxhighlight', content = content, args = { lang = 'wikitext' } } end
return p

.ts--sourceview .mw-highlight pre {
	white-space: pre-wrap;
}

