/*
 https://starcitizen.tools/Module:Mbox/styles.css 에서 가져옴. 일부 수정됨.
*/

.ts--notice {
	position: relative;
	display: flex;
	flex-direction: column;
	background-color: var(--color-surface-1);
	border: var(--border-base);
	border-radius: 8px;
}

.ts--notice-title {
	display: flex;
	align-items: center;
}

.ts--notice-icon img {
	display: block;
	width: 1rem;
	height: auto;
	opacity: 0.6;
	margin-right: 0.5rem;
}

.ts--notice-text {
	position: absolute;
	top: 100%;
	left: 0;
	right: 0;
	z-index: 10;
	margin-inline: -1px;
	box-sizing: border-box;
	background-color: var(--color-surface-1);
	border-inline: var(--border-base);
	border-bottom: var(--border-base);
	border-bottom-left-radius: 8px;
	border-bottom-right-radius: 8px;
	opacity: 0;
	visibility: hidden;
}

.ts--notice-text::before {
	content: '';
	display: block;
	position: absolute;
	top: 0;
	left: 1rem;
	right: 1rem;
	height: 1px;
	background: var(--border-color-subtle);
}


.ts--notice.ts--notice-textexist {
	border-bottom-style: double;
	border-bottom-width: 4px;
}

.ts--notice.ts--notice-textexist:hover {
	border-bottom-left-radius: 0;
	border-bottom-right-radius: 0;
}

.ts--notice.ts--notice-textexist:hover .ts--notice-text {
	opacity: 1;
	visibility: visible;
}

